{
  "variables": [
    {
      "id": "review-layer",
      "label": "Review Layer Applied (Layer 1 / Layer 2 / Layer 3)",
      "role": "independent",
      "distribution": "Categorical(automation, behavioral, structural)"
    },
    {
      "id": "change-type",
      "label": "Type of Code Change (UI, logic, auth, infra, etc.)",
      "role": "independent",
      "distribution": "Categorical(ui-ux, business-logic, auth-security, db-schema, infra, dependency, core-model)"
    },
    {
      "id": "spot-check-flag",
      "label": "Whether Change Was Randomly Spot-Checked (~1 in 10)",
      "role": "independent",
      "distribution": "Bernoulli(0.1)"
    },
    {
      "id": "ai-generated",
      "label": "Whether Code Was AI-Generated vs. Human-Written",
      "role": "independent",
      "distribution": "Bernoulli(p)"
    },
    {
      "id": "defect-rate-post-merge",
      "label": "Post-Merge Defect Rate (defects per unit time or per change)",
      "role": "dependent",
      "distribution": "Poisson(lambda)"
    },
    {
      "id": "reviewer-time",
      "label": "Reviewer Time Per Review Session (minutes)",
      "role": "dependent",
      "distribution": "Normal(mu, sigma)"
    },
    {
      "id": "feature-throughput",
      "label": "Feature Throughput (features shipped per unit time)",
      "role": "dependent",
      "distribution": "Normal(mu, sigma)"
    },
    {
      "id": "onboarding-time",
      "label": "Onboarding Time for New Users (minutes or sessions to proficiency)",
      "role": "dependent",
      "distribution": "Normal(mu, sigma)"
    },
    {
      "id": "reviewer-engagement",
      "label": "Reviewer Engagement / Rubber-Stamping Rate (qualitative or proxy)",
      "role": "dependent"
    },
    {
      "id": "coverage-threshold",
      "label": "Automated Test Coverage Threshold (%)",
      "role": "control",
      "distribution": "Continuous(0, 100)"
    },
    {
      "id": "mutation-score",
      "label": "Mutation Testing Score (%)",
      "role": "control",
      "distribution": "Continuous(0, 100)"
    },
    {
      "id": "walkthrough-staleness",
      "label": "Staleness of Behavioral Walkthrough Items (stale vs. current)",
      "role": "confounding",
      "distribution": "Bernoulli(p_stale)"
    },
    {
      "id": "team-size",
      "label": "Team Size (number of contributors)",
      "role": "confounding",
      "distribution": "Discrete(2, 3, ...)"
    },
    {
      "id": "change-volume",
      "label": "Volume of Changes Per Unit Time (change rate)",
      "role": "confounding",
      "distribution": "Poisson(lambda)"
    },
    {
      "id": "diff-coverage-link",
      "label": "Diff-Coverage Linking Active (yes/no)",
      "role": "control",
      "distribution": "Bernoulli(1)"
    }
  ],
  "hypotheses": [
    {
      "id": "H1",
      "statement": "Adoption of three-layer behavioral review is associated with a lower post-merge defect rate compared to traditional line-by-line code review alone.",
      "nullHypothesis": "There is no difference in post-merge defect rate between the three-layer review system and traditional code review.",
      "testSuggestion": "Two-sample Poisson rate ratio test (or negative binomial regression) comparing defect counts per change-volume across pre/post adoption periods or across teams using different review models."
    },
    {
      "id": "H2",
      "statement": "Reviewer time per session grows sublinearly with change volume under the three-layer model (i.e., reviewer effort scales better than linearly).",
      "nullHypothesis": "Reviewer time per session increases at least linearly with change volume (slope >= 1 in a log-log regression).",
      "testSuggestion": "Log-log ordinary least squares regression of reviewer time on change volume; test whether the estimated slope coefficient is significantly less than 1 using a one-sided t-test."
    },
    {
      "id": "H3",
      "statement": "Changes that undergo random spot-check (Layer 3 inspection) have a higher detected structural defect rate than changes reviewed only behaviorally (Layer 2).",
      "nullHypothesis": "The structural defect detection rate is the same whether or not a change is spot-checked.",
      "testSuggestion": "Two-proportion z-test (or Fisher's exact test for small samples) comparing the proportion of spot-checked vs. non-spot-checked changes where structural defects are found."
    },
    {
      "id": "H4",
      "statement": "Walkthroughs with stale behavioral items are associated with higher post-merge defect rates than walkthroughs with fully current items.",
      "nullHypothesis": "Walkthrough staleness has no effect on post-merge defect rate.",
      "testSuggestion": "Poisson or negative binomial regression with defect count as outcome and walkthrough-staleness indicator as predictor, controlling for change-type and change-volume."
    },
    {
      "id": "H5",
      "statement": "Feature throughput (features shipped per unit time) is higher under the three-layer review system than under traditional code review.",
      "nullHypothesis": "Feature throughput is the same under both review systems.",
      "testSuggestion": "Two-sample t-test or Mann-Whitney U test on feature throughput rates across pre/post periods, accounting for change-volume as a covariate via ANCOVA."
    },
    {
      "id": "H6",
      "statement": "User onboarding time decreases as the behavioral walkthrough-based onboarding guide matures (accumulates more verified items over time).",
      "nullHypothesis": "Onboarding time is uncorrelated with the number of verified onboarding walkthrough items.",
      "testSuggestion": "Pearson or Spearman correlation between onboarding guide item count (at time of onboarding) and measured onboarding time; or simple linear regression with onboarding-item count as predictor."
    },
    {
      "id": "H7",
      "statement": "Higher automated test coverage is associated with fewer post-merge defects escaping to production.",
      "nullHypothesis": "Automated test coverage level is not associated with post-merge defect rate.",
      "testSuggestion": "Spearman rank correlation or Poisson regression of defect rate on coverage percentage; consider breakpoint/threshold analysis around coverage levels specified in policy."
    },
    {
      "id": "H8",
      "statement": "The proportion of spot-checked changes revealing problems increases when spot check frequency drops below the target rate (~10%), indicating process drift.",
      "nullHypothesis": "The defect detection rate among spot-checked changes is independent of the spot-check frequency.",
      "testSuggestion": "Logistic regression or two-proportion z-test comparing defect detection rates in periods of low vs. normal spot-check frequency; time-series analysis for drift detection."
    }
  ],
  "assumptions": [
    "Independence of observations: individual code changes and their associated review outcomes are treated as independent units of analysis.",
    "Stationarity: the defect-generating process is approximately stationary within measurement periods, i.e., product complexity and team skill do not change dramatically during measurement.",
    "Normality of reviewer time and throughput measures, at least approximately, for t-test and regression analyses (or sufficiently large n for CLT to apply).",
    "Poisson-distributed defect counts: defects occur independently and at a roughly constant rate per unit of change volume.",
    "Random assignment validity: the ~1-in-10 spot-check selection is genuinely random and not biased toward suspicious or safe changes.",
    "Consistent defect classification: what counts as a 'defect found post-merge' is defined and applied consistently across time and reviewers.",
    "Non-interference between layers: the output of Layer 1 automation does not systematically bias what behavioral or structural reviewers attend to (or this is modeled explicitly).",
    "Single reviewer fidelity: the reviewer's behavioral verification effort is approximately uniform across sessions (rubber-stamping is not systematically correlated with change type or volume in unmeasured ways).",
    "Walkthrough completeness as a proxy: diff-coverage linking is assumed to provide a valid (if imperfect) measure of walkthrough coverage.",
    "Team size stability: the two-person team assumption holds during the measurement period; findings may not generalize once team size increases.",
    "No carry-over effects: defects caught in one review session do not reduce the pool of detectable defects in subsequent sessions in ways that confound comparisons.",
    "Author classification honesty: when risk classification is author-assigned, misclassification rates are low enough or randomly distributed enough not to systematically bias layer assignment."
  ],
  "sampleRequirements": "For defect rate comparisons (H1, H4, H7): at least 50-100 merged changes per condition to achieve adequate power for Poisson rate tests at alpha=0.05, given expected low base defect rates. For spot-check proportion tests (H3, H8): at least 30 spot-checked changes and 30 non-spot-checked changes required; at 10% spot-check rate this implies roughly 300+ total changes observed. For reviewer time regression (H2): at least 30 review sessions spanning a meaningful range of change volumes. For onboarding time (H6): at least 15-20 distinct onboarding events, which may require extended observation given small team size. Given the two-person team context, longitudinal within-team designs and interrupted time series are likely more feasible than between-group comparisons.",
  "summary": "This document proposes a three-layer code review system (automation, behavioral, structural) for AI-assisted development teams, and implies a set of causal and associative claims about how review layer assignment, spot-check frequency, walkthrough freshness, and test coverage affect downstream outcomes including defect rate, reviewer effort, feature throughput, and onboarding efficiency. The primary statistical challenge is disentangling the effects of review structure from confounds such as change volume, team size, and product maturity in a small-team longitudinal setting. Most hypotheses are best evaluated via Poisson regression models for count outcomes and linear or log-log regression for continuous outcomes, with the two-person team size severely limiting between-group designs and favoring interrupted time series or within-team before/after analyses. Key unmeasured confounds include reviewer engagement quality (rubber-stamping), author classification honesty, and the evolving complexity of the product over time."
}
